#include <stdio.h>
#include <string.h>
int main() {
    int T, L, H;
    char S[100001];
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &L, &H);
        scanf("%s", S);
        int max_freq = 0, max_len = 0;
        for (int len = L; len <= H; len++) {
            for (int i = 0; i <= strlen(S) - len; i++) {
                char substr[len + 1];
                strncpy(substr, S + i, len);
                substr[len] = '\0';
                int freq = 0;
                for (int j = 0; j <= strlen(S) - len; j++) {
                    if (strncmp(S + j, substr, len) == 0) freq++;
                }
                if (freq > max_freq || (freq == max_freq && len > max_len)) {
                    max_freq = freq;
                    max_len = len;
                }
            }
        }
        printf("%d %d\n", max_freq, max_len);
    }
    return 0;
}

