import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int L = sc.nextInt(), H = sc.nextInt();
            String S = sc.next();
            int max_freq = 0, max_len = 0;
            for (int len = L; len <= H; len++) {
                for (int i = 0; i <= S.length() - len; i++) {
                    String substr = S.substring(i, i + len);
                    int freq = 0;
                    for (int j = 0; j <= S.length() - len; j++) {
                        if (S.substring(j, j + len).equals(substr)) freq++;
                    }
                    if (freq > max_freq || (freq == max_freq && len > max_len)) {
                        max_freq = freq;
                        max_len = len;
                    }
                }
            }
            System.out.println(max_freq + " " + max_len);
        }
    }
}

